def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    def harmonic_sum(x):
        s = 0.0
        for i in range(1, 20):
            s += np.sin(x / i) / i
        return s
    def complex_series(val, m):
        total = 0.0
        sign = 1
        for i in range(1, m + 10):
            power = (val * i) ** 1.1
            total += sign * np.exp(-power) * np.cos(val * i * 0.7) / (i ** 0.9)
            sign *= -1
        return total
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 7:
            for x in range(7, 0, -1):
                for y in range(2, x + 5):
                    val = (ratio - x) ** 6
                    part = val / (y * 1.1 + 2)
                    priority += part * np.sin(ratio * y / (x + 2)) * harmonic_sum(ratio + y)
            priority += (np.log1p(ratio - 7) * np.sin(ratio * 1.3)) ** 2
            if bin_cap < item * 0.5:
                priority += np.sqrt(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio) * 3.5
        elif 4 < ratio <= 7:
            s = 0.0
            for p in range(2, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    power = ((ratio - p) ** 4) / (q + 0.7)
                    s += np.tanh(np.sin(ratio * p) * power) * 1.4
            priority = s + (np.log(ratio) * 12) - np.tanh(ratio - 4) * 2.5
            if (i * int(item * 1.1)) % 5 == 0:
                priority *= 1.5
            else:
                priority /= 1.5
        elif 2 <= ratio <= 4:
            s1 = 0.0
            for r in range(1, 15):
                s1 += ((ratio - 2) ** r) / (r * 2.2) * np.cos(r * ratio * 1.1)
            s2 = 0.0
            for k in range(1, 7):
                s2 += ((4 - ratio) ** k) / (k + 0.3) * np.sin(k * ratio * 2)
            priority = s1 * np.cos(8 * ratio) - np.log(ratio) * 7 + np.tanh(3.5 * (4 - ratio)) * 2 + s2 * 0.6
        elif 1 <= ratio < 2:
            s = 0.0
            for n in range(1, 20):
                s += ((2 - ratio) ** n) / (n * 3) * np.cos(n * ratio * 0.9)
            penalty = 0.0
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 8):
                priority += np.sin(m * ratio * i * 0.7) * ((ratio - 1) ** m) / (m + 0.5)
        elif 0.5 <= ratio < 1:
            s = 0.0
            for n in range(1, 25):
                s += ((1 - ratio) ** n) / (n * 5)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 10):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.8
        elif 0.2 <= ratio < 0.5:
            s = 0.0
            for k in range(1, 20):
                s += ((0.5 - ratio) ** k) / (k * 3.5) * np.cos(k * ratio * 2.2)
            priority = s + 1.5 / (bin_cap + 4)
            if int(item * 1.5) % 6 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 12):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0.0
            for t in range(1, 15):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 7 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.2) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 9) * np.cos(item * u * 0.95)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-2.5 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
